import { isSocialAllowed, createElement, deepMerge, getTextLabel, decorateIcons } from './common.js';
import { loadScript, loadCSS } from './aem.js';

export const VIDEO_JS_SCRIPT = '/scripts/videojs/video.min.js';
export const VIDEO_JS_CSS = '/scripts/videojs/video-js.min.css';
/* global videojs */

// videoURLRegex: verify if a given string follows a specific pattern indicating it is a video URL
// videoIdRegex: extract the video ID from the URL
export const AEM_ASSETS = {
  aemCloudDomain: '.adobeaemcloud.com',
  videoURLRegex: /\/assets\/urn:aaid:aem:[\w-]+\/play/,
  videoIdRegex: /urn:aaid:aem:[0-9a-fA-F-]+/,
};

export const youtubeVideoRegex =
  /^(?:(?:https?:)?\/\/)?(?:(?:(?:www|m(?:usic)?)\.)?youtu(?:\.be|be\.com)\/(?:shorts\/|live\/|v\/|e(?:mbed)?\/|watch(?:\/|\?(?:\S+=\S+&)*v=)|oembed\?url=https?%3A\/\/(?:www|m(?:usic)?)\.youtube\.com\/watch\?(?:\S+=\S+&)*v%3D|attribution_link\?(?:\S+=\S+&)*u=(?:\/|%2F)watch(?:\?|%3F)v(?:=|%3D))?|www\.youtube-nocookie\.com\/embed\/)([\w-]{11})[?&#]?\S*$/;

const { aemCloudDomain, videoURLRegex } = AEM_ASSETS;

export const videoTypes = {
  aem: 'aem',
  youtube: 'youtube',
  local: 'local',
  both: 'both',
};

export const standardVideoConfig = {
  autoplay: false,
  muted: false,
  controls: true,
  disablePictureInPicture: false,
  currentTime: 0,
  playsinline: true,
};

export const videoConfigs = {};

async function waitForVideoJs() {
  return new Promise((resolve) => {
    const scriptTag = document.querySelector(`head > script[src="${VIDEO_JS_SCRIPT}"]`);
    const cssLink = document.querySelector(`head > link[href="${VIDEO_JS_CSS}"]`);
    const isJsLoaded = scriptTag && scriptTag.dataset.loaded;
    const isCSSLoaded = cssLink && cssLink.dataset.loaded;
    if (!isJsLoaded || !isCSSLoaded) {
      const successHandler = () => {
        document.removeEventListener('videojs-loaded', successHandler);
        resolve();
      };

      document.addEventListener('videojs-loaded', successHandler);
      return;
    }

    resolve();
  });
}

/**
 * Attempts to safely play a media element or player object,
 * catching and logging `NotAllowedError` and other playback-related errors.
 *
 * This is useful for browsers that block autoplay (especially Safari and iOS)
 * unless the video is muted or triggered by user interaction.
 *
 * @param {HTMLMediaElement | { play: () => Promise<void> | void }} playable
 *   - A native <video> or <audio> element, or a player object like video.js with a `.play()` method.
 */
function safePlay(playable) {
  try {
    const result = playable.play();
    if (result instanceof Promise) {
      result.catch((err) => {
        if (err.name === 'NotAllowedError') {
          console.warn('Autoplay prevented by browser:', err);
        } else {
          console.error('Error playing video:', err);
        }
      });
    }
  } catch (err) {
    if (err.name === 'NotAllowedError') {
      console.warn('Autoplay prevented by browser:', err);
    } else {
      console.error('Error playing video:', err);
    }
  }
}

/**
 * Observes a target element and triggers autoplay when it is almost fully visible
 * in the viewport, and pauses it when it is almost fully out of view.
 *
 * Uses a visibility tolerance (≈99% visible / ≈1% visible) to avoid strict
 * equality checks that can be unreliable.
 *
 * @param {Object} options - Configuration options.
 * @param {HTMLElement} options.target - The element to observe.
 * @param {Function} options.play - Callback invoked when the element becomes sufficiently visible.
 * @param {Function} options.pause - Callback invoked when the element becomes sufficiently hidden.
 * @param {number|number[]} [options.threshold] - Custom IntersectionObserver thresholds.
 *        Defaults to [0, 0.01, 0.99, 1].
 * @param {boolean} [options.once=false] - If true, stops observing after the first successful play.
 * @param {number} [options.debounceMs=0] - Delay (in ms) before invoking the play callback.
 *
 * @returns {IntersectionObserver} The created observer instance (can be disconnected externally).
 */
function observeAutoplayWhenVisible({ target, play, pause, threshold, once = false, debounceMs = 0 }) {
  const FULLY_VISIBLE_RATIO = 0.99;
  const FULLY_HIDDEN_RATIO = 0.01;

  const thresholds = threshold ?? [0, FULLY_HIDDEN_RATIO, FULLY_VISIBLE_RATIO, 1];

  let timeoutId;

  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        clearTimeout(timeoutId);

        const { intersectionRatio, isIntersecting } = entry;

        const isVisible = isIntersecting && intersectionRatio >= FULLY_VISIBLE_RATIO;
        const isHidden = !isIntersecting || intersectionRatio <= FULLY_HIDDEN_RATIO;

        if (isVisible) {
          timeoutId = setTimeout(() => {
            play();
            if (once) {
              observer.unobserve(entry.target);
            }
          }, debounceMs);
        } else if (isHidden) {
          pause();
        }
      });
    },
    { threshold: thresholds },
  );

  observer.observe(target);

  return observer;
}

/**
 * Attaches an autoplay observer to a video.js player so that it plays/pause based on visibility.
 *
 * @param {HTMLVideoElement} videoElement - The video element used by the player.
 * @param {Object} player - The video.js player instance.
 * @returns {IntersectionObserver} The observer instance.
 */
function setupAutopause(videoElement, player) {
  return observeAutoplayWhenVisible({
    target: videoElement,
    play: () => safePlay(player),
    pause: () => player.pause(),
    debounceMs: 100,
  });
}

/**
 * Waits until a given DOM element is present in the document and has a parent matching a selector,
 * then calls the callback with the found wrapper as an argument.
 *
 * This is useful for situations where elements may be attached to the DOM asynchronously,
 * or when wrappers/components may appear after a delay (such as with dynamic libraries).
 *
 * @param {HTMLElement} el - The DOM element to check for presence and wrapping.
 * @param {string} wrapperSelector - The CSS selector for the required ancestor/wrapper.
 * @param {(wrapper: HTMLElement|null) => void} cb - The callback invoked when the condition is met
 *        (with the wrapper as argument) or when retries are exhausted (with `null`).
 * @param {number} [maxTries=40] - Maximum number of polling attempts before giving up (default: 40).
 * @param {number} [delay=50] - Delay in milliseconds between polling attempts (default: 50ms).
 */
export function whenInDOMAndWrapped(el, wrapperSelector, cb, maxTries = 40, delay = 50) {
  let tries = 0;

  function check() {
    const inDOM = document.body.contains(el);
    const wrapper = el.closest ? el.closest(wrapperSelector) : null;
    if (inDOM && wrapper) {
      cb(wrapper);
    } else if (tries < maxTries) {
      tries++;
      setTimeout(check, delay);
    } else {
      cb(null);
    }
  }
  check();
}

export async function setupPlayer(url, videoContainer, config, video) {
  let videoElement = video;
  if (!videoElement) {
    videoElement = document.createElement('video');
    videoElement.id = `video-${Math.random().toString(36).substr(2, 9)}`;
  }

  videoElement.classList.add('video-js');

  if (config.playsinline || config.autoplay) {
    videoElement.setAttribute('playsinline', '');
  }

  videoContainer.append(videoElement);

  const videojsConfig = {
    ...config,
    preload: config.poster && !config.autoplay ? 'none' : 'auto',
    bigPlayButton: config.controls ?? true,
    controls: config.controls ?? false,
    autoplay: false, // Disable built-in autoplay
  };

  if (config.muted) {
    videojsConfig.muted = true;
  }

  await waitForVideoJs();

  if (!videojs) {
    throw new Error('Video.js is not loaded');
  }

  const player = videojs(videoElement, videojsConfig);
  player.src(url);

  // Ensure player does not autoplay prematurely
  player.pause();

  player.ready(() => {
    if (config.autoplay) {
      // Always get the actual <video> from the DOM after ready
      const currentVideoElement = videoContainer.querySelector('video');
      whenInDOMAndWrapped(currentVideoElement, '.v2-video, .v2-embed', (wrapper) => {
        if (wrapper) {
          setupAutopause(currentVideoElement, player);
        } else {
          player.play();
        }
      });
    }
  });

  return player;
}

export function getDeviceSpecificVideoUrl(videoUrl) {
  const { userAgent } = navigator;
  const isIOS = /iPad|iPhone|iPod/.test(userAgent);
  const isSafari =
    /Safari/i.test(userAgent) && !/Chrome/i.test(userAgent) && !/CriOs/i.test(userAgent) && !/Android/i.test(userAgent) && !/Edg/i.test(userAgent);

  const manifest = isIOS || isSafari ? 'manifest.m3u8' : 'manifest.mpd';
  return videoUrl.replace(/manifest\.mpd|manifest\.m3u8|play/, manifest);
}

export const addVideoConfig = (videoId, props = {}) => {
  if (!videoConfigs[videoId]) {
    videoConfigs[videoId] = deepMerge({}, standardVideoConfig);
  }
  deepMerge(videoConfigs[videoId], props);
};

export const getVideoConfig = (videoId) => videoConfigs[videoId];

export function isLowResolutionVideoUrl(url) {
  return url.split('?')[0].endsWith('.mp4');
}

export function isAEMVideoUrl(url) {
  return videoURLRegex.test(url);
}

export function isValidVideoUrl(url) {
  if (typeof url !== 'string' || !url.trim()) {
    return false;
  }

  return isLowResolutionVideoUrl(url) || isAEMVideoUrl(url);
}

export function isYoutubeVideoUrl(url) {
  return youtubeVideoRegex.test(url);
}

export function getYoutubeVideoId(url) {
  const match = url.match(youtubeVideoRegex);

  return match?.length >= 2 ? match[1] : '';
}

/**
 * Builds a YouTube embed URL using the privacy-enhanced (youtube-nocookie) domain.
 * Applies relevant player parameters such as autoplay, mute, controls,
 * playsinline and loop.
 *
 * @param {string} videoId - The 11-character YouTube video ID.
 * @param {Object} [playerConfig={}] - Player configuration options.
 * @param {boolean} [playerConfig.autoplay] - Whether the video should autoplay.
 * @param {boolean} [playerConfig.muted] - Whether the video should start muted.
 * @param {boolean} [playerConfig.controls] - Whether native YouTube controls are shown.
 * @param {boolean} [playerConfig.playsinline] - Whether playback should occur inline on mobile.
 * @param {boolean} [playerConfig.loop] - Whether the video should loop.
 * @returns {string} Fully qualified YouTube embed URL.
 */
function buildYouTubeEmbedUrl(videoId, playerConfig = {}) {
  const searchParams = new URLSearchParams();

  searchParams.set('rel', '0');
  searchParams.set('modestbranding', '1');
  searchParams.set('autoplay', playerConfig.autoplay ? '1' : '0');
  searchParams.set('mute', playerConfig.muted ? '1' : '0');
  searchParams.set('controls', playerConfig.controls === false ? '0' : '1');
  searchParams.set('playsinline', playerConfig.playsinline ? '1' : '0');

  if (playerConfig.loop) {
    searchParams.set('loop', '1');
    searchParams.set('playlist', videoId);
  }

  return `https://www.youtube-nocookie.com/embed/${videoId}?${searchParams.toString()}`;
}

/**
 * Creates a YouTube <iframe> element using the privacy-enhanced embed URL.
 * Applies accessibility, loading and feature permissions.
 *
 * @param {string} videoId - The 11-character YouTube video ID.
 * @param {Object} [playerConfig={}] - Player configuration options.
 * @param {string} [playerConfig.title] - Optional accessible title for the iframe.
 * @returns {HTMLIFrameElement} The configured YouTube iframe element.
 */
function createYouTubeIframe(videoId, playerConfig = {}) {
  const embedUrl = buildYouTubeEmbedUrl(videoId, playerConfig);

  return createIframe(embedUrl, {
    props: {
      title: playerConfig.title || 'YouTube video',
      loading: 'lazy',
      referrerpolicy: 'strict-origin-when-cross-origin',
      allow: 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share',
    },
  });
}

/**
 * Adds custom play/pause controls for a YouTube IFrame API player.
 * Syncs UI state with the player's playback state.
 *
 * @param {HTMLElement} container - The wrapper element where controls are appended.
 * @param {YT.Player} player - The YouTube IFrame API player instance.
 * @returns {{ update: () => void }} Control API exposing an update method to resync UI state.
 */
function setYouTubeControls(container, player) {
  const button = createElement('button', {
    props: { type: 'button', class: 'v2-video__playback-button' },
  });

  const pauseIcon = createElement('span', { classes: ['icon', 'icon-pause-video'] });
  const playIcon = createElement('span', { classes: ['icon', 'icon-play-video'] });

  button.append(pauseIcon, playIcon);
  container.appendChild(button);
  decorateIcons(button);

  const pauseLabel = getTextLabel('video_helper:pause_video_label');
  const playLabel = getTextLabel('video_helper:play_video_label');

  const PlayerState = window.YT?.PlayerState;

  const isPlayingState = (state) => PlayerState && (state === PlayerState.PLAYING || state === PlayerState.BUFFERING);

  const update = () => {
    const state = player.getPlayerState?.();
    const isPlaying = isPlayingState(state);

    pauseIcon.style.display = isPlaying ? 'flex' : 'none';
    playIcon.style.display = isPlaying ? 'none' : 'flex';
    button.setAttribute('aria-label', isPlaying ? pauseLabel : playLabel);
    button.setAttribute('aria-pressed', String(isPlaying));
  };

  update();

  button.addEventListener('click', (e) => {
    e.preventDefault();
    e.stopPropagation();

    const state = player.getPlayerState?.();
    if (isPlayingState(state)) {
      player.pauseVideo?.();
    } else {
      player.playVideo?.();
    }

    requestAnimationFrame(update);
  });

  return { update };
}

/**
 * Adds a custom mute/unmute toggle for a YouTube IFrame API player.
 * Keeps the button UI in sync with the player's mute state.
 *
 * Due to the asynchronous nature of the YouTube API, the UI is resynced
 * immediately and shortly after toggling to ensure accuracy.
 *
 * @param {HTMLElement} container - The wrapper element where the toggle is appended.
 * @param {YT.Player} player - The YouTube IFrame API player instance.
 * @returns {{ update: () => void, syncUI: () => void }} Control API exposing
 *          methods to manually resync the UI with the player state.
 */
function setYouTubeMuteToggle(container, player) {
  const button = createElement('button', {
    classes: 'video__mute-toggle-button',
    props: { type: 'button' },
  });

  const mutedIcon = createElement('span', { classes: ['icon', 'icon-muted'] });
  const unmutedIcon = createElement('span', { classes: ['icon', 'icon-unmuted'] });

  button.append(mutedIcon, unmutedIcon);
  container.appendChild(button);
  decorateIcons(button);

  const muteLabel = getTextLabel('video_helper:mute_video_aria_label');
  const unmuteLabel = getTextLabel('video_helper:unmute_video_aria_label');

  const isMuted = () => player?.isMuted?.() === true;

  const update = () => {
    const muted = isMuted();
    mutedIcon.style.display = muted ? 'flex' : 'none';
    unmutedIcon.style.display = muted ? 'none' : 'flex';
    button.setAttribute('aria-label', muted ? unmuteLabel : muteLabel);
    button.setAttribute('aria-pressed', String(muted));
  };

  let delayedSyncId;

  // YouTube Iframe API updates mute state asynchronously.
  // We sync UI immediately, on next frame, and with a short delay
  // to ensure the button reflects the actual player state.
  const syncUI = () => {
    update();
    requestAnimationFrame(update);

    if (delayedSyncId) {
      clearTimeout(delayedSyncId);
    }
    delayedSyncId = setTimeout(update, 200);
  };

  syncUI();

  button.addEventListener('click', (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (isMuted()) {
      player.unMute();
    } else {
      player.mute();
    }

    syncUI();
  });

  return { update, syncUI };
}

let ytPromise;

/**
 * Lazily loads the YouTube IFrame API and returns a shared promise.
 *
 * Ensures the API script is loaded only once.
 * Resolves when `window.YT.Player` becomes available, and rejects on
 * timeout or script loading failure.
 *
 * @returns {Promise<void>} A promise that resolves when the YouTube
 *          IFrame API is ready to use.
 */
export function loadYouTubeIframeAPI() {
  if (ytPromise) {
    return ytPromise;
  }

  ytPromise = new Promise((resolve, reject) => {
    if (window.YT && typeof window.YT.Player === 'function') {
      resolve();
      return;
    }

    const timeoutId = setTimeout(() => {
      ytPromise = undefined;
      reject(new Error('YouTube Iframe API load timeout'));
    }, 15000);

    const previousReady = window.onYouTubeIframeAPIReady;

    window.onYouTubeIframeAPIReady = () => {
      if (typeof previousReady === 'function') {
        previousReady();
      }

      clearTimeout(timeoutId);

      if (window.YT && typeof window.YT.Player === 'function') {
        resolve();
      } else {
        ytPromise = undefined;
        reject(new Error('YouTube Iframe API ready callback fired but YT.Player is unavailable'));
      }
    };

    loadScript('https://www.youtube.com/iframe_api').catch((err) => {
      clearTimeout(timeoutId);
      ytPromise = undefined;
      reject(err);
    });
  });

  return ytPromise;
}

/**
 * Creates a YouTube player using the YouTube IFrame API and mounts it into the given element.
 *
 * Supports:
 * - Poster-first rendering (hide iframe until playback starts)
 * - Optional custom controls UI (when `playerConfig.controls === false`)
 * - Optional viewport-based autoplay/pause (when `playerConfig.autoplay === true`)
 *
 * @param {string} videoId - The YouTube video ID (11 chars).
 * @param {string} mountId - The DOM id of the element where the player will be mounted.
 * @param {Object} playerConfig - Player options (e.g. autoplay, muted, controls, playsinline, loop).
 * @param {Object} [options] - Optional DOM helpers.
 * @param {HTMLElement} [options.container] - Wrapper container used for custom UI and/or autoplay observation.
 * @param {HTMLPictureElement|HTMLElement} [options.poster] - Poster element to show before playback (will be hidden on play).
 * @returns {Promise<any>} Resolves to the created YouTube player instance.
 */
async function createYouTubeApiPlayer(videoId, mountId, playerConfig, { container, poster } = {}) {
  await loadYouTubeIframeAPI();

  let controlsUI;
  let muteUI;
  let autoplayObserver;

  const player = new window.YT.Player(mountId, {
    videoId,
    playerVars: {
      rel: 0,
      modestbranding: 1,
      autoplay: 0,
      mute: playerConfig.muted ? 1 : 0,
      controls: playerConfig.controls === false ? 0 : 1,
      playsinline: playerConfig.playsinline ? 1 : 0,
      loop: playerConfig.loop ? 1 : 0,
      playlist: playerConfig.loop ? videoId : undefined,
    },
    events: {
      onReady: (e) => {
        const ytPlayer = e.target;
        const iframe = ytPlayer.getIframe();

        if (poster) {
          iframe.style.display = 'none';
        }

        if (playerConfig.controls === false && container) {
          controlsUI = setYouTubeControls(container, ytPlayer);
          muteUI = setYouTubeMuteToggle(container, ytPlayer);

          controlsUI.update?.();
          muteUI.syncUI?.();
        }

        if (playerConfig.autoplay) {
          const targetEl = container || iframe;

          if (!autoplayObserver) {
            autoplayObserver = observeAutoplayWhenVisible({
              target: targetEl,
              play: () => ytPlayer.playVideo(),
              pause: () => ytPlayer.pauseVideo(),
              debounceMs: 100,
            });
          }
        }
      },

      onStateChange: (evt) => {
        if (poster && evt.data === window.YT.PlayerState.PLAYING) {
          const iframe = evt.target.getIframe();
          poster.style.display = 'none';
          iframe.style.display = '';
        }

        controlsUI?.update?.();
        muteUI?.update?.();
      },
    },
  });

  return player;
}

/**
 * Creates a wrapper element for a YouTube video.
 *
 * Depending on the provided options, this will:
 * - Render a lightweight iframe embed (default behavior)
 * - Render a poster-first embed that initializes the iframe on click
 * - Initialize a full YouTube IFrame API player when custom controls are required
 *
 * @param {string} src - The YouTube URL.
 * @param {string} [className=''] - Additional CSS class(es) applied to the wrapper.
 * @param {Object} [videoParams={}] - Player options (autoplay, muted, controls, loop, playsinline).
 * @param {HTMLElement|null} [poster=null] - Optional poster element displayed before playback.
 * @returns {HTMLElement|null} The wrapper element containing the video, or null if the URL is invalid.
 */
function createYouTubeVideoWrapper(src, className = '', videoParams = {}, poster = null) {
  const videoId = getYoutubeVideoId(src);
  if (!videoId) {
    return null;
  }

  const wrapper = document.createElement('div');
  wrapper.classList.add('video-wrapper');

  const classes = className.trim();
  if (classes) {
    wrapper.classList.add(...classes.split(/\s+/));
  }

  const hasNativeControls = videoParams.controls !== false;

  if (hasNativeControls) {
    if (poster && !videoParams.autoplay) {
      wrapper.append(poster);
      addPlayIcon(wrapper);

      wrapper.addEventListener(
        'click',
        (e) => {
          e.preventDefault();
          wrapper.replaceChildren(createYouTubeIframe(videoId, { ...videoParams, autoplay: true }));
        },
        { once: true },
      );

      return wrapper;
    }

    wrapper.append(createYouTubeIframe(videoId, videoParams));
    return wrapper;
  }

  if (poster) {
    wrapper.append(poster);
  }

  const mount = createElement('div', {
    props: { id: `yt-${Math.random().toString(36).slice(2)}` },
  });

  wrapper.append(mount);

  createYouTubeApiPlayer(videoId, mount.id, videoParams, {
    container: wrapper,
    poster,
  }).catch(console.error);

  return wrapper;
}

export function isVideoLink(link) {
  if (!(link instanceof HTMLAnchorElement)) {
    return false;
  }

  const href = link.getAttribute('href') || '';
  if (!href) {
    return false;
  }

  return (
    (isYoutubeVideoUrl(href) || href.includes('player.restream.io') || videoURLRegex.test(href) || isLowResolutionVideoUrl(href)) &&
    link.closest('.block.embed') === null
  );
}

export function selectVideoLink(links, preferredType, videoType = videoTypes.both) {
  const linksArray = Array.isArray(links) ? links : [...links];
  const hasConsentForSocialVideos = isSocialAllowed();
  const isTypeBoth = videoType === videoTypes.both;
  const prefersYouTube = (hasConsentForSocialVideos && preferredType !== 'local') || (!isTypeBoth && videoType === videoTypes.youtube);

  const findLinkByCondition = (conditionFn) => linksArray.find((link) => conditionFn(link.getAttribute('href')));

  const aemVideoLink = findLinkByCondition((href) => videoURLRegex.test(href));
  const youTubeLink = findLinkByCondition((href) => isYoutubeVideoUrl(href));
  const localMediaLink = findLinkByCondition((href) => href.split('?')[0].endsWith('.mp4'));

  if (aemVideoLink) {
    return aemVideoLink;
  }
  if (prefersYouTube && youTubeLink) {
    return youTubeLink;
  }
  return localMediaLink;
}

function getVideoLinkContainer(link, usePosterAutoDetection) {
  if (!usePosterAutoDetection) {
    return link;
  }

  let poster = null;
  let level = 2;
  let parent = link;
  while (parent !== null && level >= 0) {
    poster = parent.querySelector('picture');
    if (poster) {
      break;
    }

    parent = parent.parentElement;
    level -= 1;
  }

  return poster ? parent : link;
}

function parseVideoLink(link, usePosterAutoDetection) {
  const isVideo = link ? isVideoLink(link) : false;
  if (!isVideo) {
    return null;
  }

  const container = getVideoLinkContainer(link, usePosterAutoDetection);
  const poster = container.querySelector('picture')?.cloneNode(true);

  return {
    url: link.href,
    poster,
  };
}

export function cleanupVideoLink(block, link, hasPoster) {
  const container = getVideoLinkContainer(link, hasPoster);
  // Remove empty ancestor nodes after removing video container containing link and poster image
  if (container) {
    let parent = container;
    while (parent?.parentElement?.children.length === 1 && parent?.parentElement !== block) {
      parent = parent.parentElement;
    }

    parent.remove();
  }
}

export function createLowResolutionBanner() {
  const lowResolutionMessage = getTextLabel('video_helper:low_res_message');
  const changeCookieSettings = getTextLabel('video_helper:change_cookie_settings');

  const banner = createElement('div', { classes: 'low-resolution-banner' });
  banner.innerHTML = `${lowResolutionMessage} <button class="low-resolution-banner-cookie-settings">${changeCookieSettings}</button>`;
  banner.querySelector('button').addEventListener('click', () => {
    window.OneTrust.ToggleInfoDisplay();
  });

  return banner;
}

export function showVideoModal(linkUrl, modalClasses) {
  import('../common/modal/modal-component.js').then((modal) => {
    let beforeBanner;

    if (isLowResolutionVideoUrl(linkUrl)) {
      beforeBanner = createLowResolutionBanner();
    }

    modal.showModal(linkUrl, { beforeBanner, classes: modalClasses });
  });
}

export function addVideoShowHandler(link) {
  link.classList.add('text-link-with-video');

  link.addEventListener('click', (event) => {
    event.preventDefault();

    const variantClasses = ['black'];
    const modalClasses = [...event.target.closest('.section').classList].filter((el) => el.startsWith('modal-'));
    variantClasses.forEach((variant) => {
      const index = modalClasses.findIndex((el) => el === `modal-${variant}`);

      if (index >= 0) {
        modalClasses[index] = modalClasses[index].replace('modal-', 'modal--');
      }
    });

    showVideoModal(link.getAttribute('href'), modalClasses);
  });
}

export function isSoundcloudLink(link) {
  return link.getAttribute('href').includes('soundcloud.com/player') && link.closest('.block.embed') === null;
}

export function addSoundcloudShowHandler(link) {
  link.classList.add('text-link-with-soundcloud');

  link.addEventListener('click', (event) => {
    event.preventDefault();

    const thumbnail = link.closest('div')?.querySelector('picture');
    const title = link.closest('div')?.querySelector('h1, h2, h3');
    const text = link.closest('div')?.querySelector('p:not(.button-container, .image)');

    import('../common/modal/modal-component.js').then((modal) => {
      const episodeInfo = document.createElement('div');
      episodeInfo.classList.add('modal-soundcloud');
      episodeInfo.innerHTML = `<div class="episode-image"><picture></div>
      <div class="episode-text">
          <h2></h2>
          <p></p>
      </div>`;
      episodeInfo.querySelector('picture').innerHTML = thumbnail?.innerHTML || '';
      episodeInfo.querySelector('h2').innerText = title?.innerText || '';
      episodeInfo.querySelector('p').innerText = text?.innerText || '';

      modal.showModal(link.getAttribute('href'), null, episodeInfo);
    });
  });
}

export function addPlayIcon(parent) {
  const iconWrapper = createElement('div', { classes: 'video-icon-wrapper' });
  const icon = createElement('i', { classes: ['fa', 'fa-play', 'video-icon'] });
  iconWrapper.appendChild(icon);
  parent.appendChild(iconWrapper);
}

export function wrapImageWithVideoLink(videoLink, image) {
  videoLink.innerText = '';
  videoLink.appendChild(image);
  videoLink.classList.add('link-with-video');
  videoLink.classList.remove('button', 'primary', 'text-link-with-video');

  addPlayIcon(videoLink);
}

export function createIframe(url, { parentEl, classes = [], props = {} }) {
  // iframe must be recreated every time otherwise the new history record would be created
  const iframe = createElement('iframe', {
    classes: Array.isArray(classes) ? classes : [classes],
    props: {
      frameborder: '0',
      allowfullscreen: 'allowfullscreen',
      src: url,
      ...props,
    },
  });

  if (parentEl) {
    parentEl.appendChild(iframe);
  }

  return iframe;
}

export function setPlaybackControls(container) {
  // Playback controls - play and pause button
  const playPauseButton = createElement('button', {
    props: { type: 'button', class: 'v2-video__playback-button' },
  });

  const playbackButton = createElement('button', {
    props: { type: 'button', class: 'v2-video__playback-button' },
  });
  const pauseIcon = createElement('span', { classes: ['icon', 'icon-pause-video'] });
  const playIcon = createElement('span', { classes: ['icon', 'icon-play-video'] });

  playbackButton.append(pauseIcon, playIcon);

  playPauseButton.append(...playbackButton.children);
  container.appendChild(playPauseButton);
  decorateIcons(container);

  const playIconElement = container.querySelector('.icon-play-video');
  const pauseIconElement = container.querySelector('.icon-pause-video');

  const pauseVideoLabel = getTextLabel('video_helper:pause_video_label');
  const playVideoLabel = getTextLabel('video_helper:play_video_label');

  playPauseButton.setAttribute('aria-label', pauseVideoLabel);

  const togglePlayPauseIcon = (isPaused) => {
    if (isPaused) {
      pauseIconElement.style.display = 'none';
      playIconElement.style.display = 'flex';
      playPauseButton.setAttribute('aria-label', playVideoLabel);
    } else {
      pauseIconElement.style.display = 'flex';
      playIconElement.style.display = 'none';
      playPauseButton.setAttribute('aria-label', pauseVideoLabel);
    }
  };

  const video = container.querySelector('video');
  const poster = container.querySelector('picture');
  togglePlayPauseIcon(video.paused);

  const togglePlayPause = (el) => {
    if (el.paused) {
      if (poster) {
        poster.remove();
        video.parentElement.style.display = '';
        video.style.display = '';
      }
      el.play();
    } else {
      el.pause();
    }
  };

  playPauseButton.addEventListener('click', (e) => {
    e.preventDefault();
    togglePlayPause(video);
  });
  video.addEventListener('playing', () => {
    togglePlayPauseIcon(video.paused);
  });
  video.addEventListener('pause', () => {
    togglePlayPauseIcon(video.paused);
  });
}

/**
 * Creates a toggle button that mutes or unmutes the given video element.
 * The button updates its icon and accessibility labels based on the mute state.
 *
 * @param {HTMLVideoElement} videoElement - The video element to control.
 * @returns {HTMLButtonElement|null} The mute toggle button, or null if the input is invalid.
 */
export function createMuteToggleButton(videoElement) {
  if (!videoElement || !(videoElement instanceof HTMLVideoElement)) {
    console.warn('createMuteToggleButton requires a valid HTMLVideoElement.');
    return null;
  }

  const toggleButton = createElement('button', {
    classes: 'video__mute-toggle-button',
    props: { type: 'button' },
  });

  const iconMuted = createElement('span', { classes: ['icon', 'icon-muted'] });
  const iconUnmuted = createElement('span', { classes: ['icon', 'icon-unmuted'] });

  toggleButton.append(iconMuted, iconUnmuted);
  decorateIcons(toggleButton);

  const labelMute = getTextLabel('video_helper:mute_video_aria_label');
  const labelUnmute = getTextLabel('video_helper:unmute_video_aria_label');

  /**
   * Updates the visibility of icons based on mute state.
   * @param {boolean} muted
   */
  const updateIconDisplay = (muted) => {
    iconMuted.style.display = muted ? 'flex' : 'none';
    iconUnmuted.style.display = muted ? 'none' : 'flex';
  };

  /**
   * Updates the ARIA label and pressed state based on mute state.
   * @param {boolean} muted
   */
  const updateAccessibility = (muted) => {
    toggleButton.setAttribute('aria-label', muted ? labelUnmute : labelMute);
    toggleButton.setAttribute('aria-pressed', muted.toString());
  };

  /**
   * Applies all UI and accessibility updates.
   */
  const updateToggleUI = () => {
    const isMuted = videoElement.muted;
    updateIconDisplay(isMuted);
    updateAccessibility(isMuted);
  };

  updateToggleUI();

  toggleButton.addEventListener('click', (event) => {
    event.preventDefault();
    videoElement.muted = !videoElement.muted;
    updateToggleUI();
  });

  return toggleButton;
}

/**
 * Appends a mute/unmute toggle button to a video container.
 * @param {HTMLElement} container - The container that holds the <video> element.
 */
export function appendMuteToggleButton(container) {
  const videoElement = container.querySelector('video');
  if (!videoElement) {
    return;
  }

  const muteToggleButton = createMuteToggleButton(videoElement);
  container.appendChild(muteToggleButton);
}

function createProgressivePlaybackVideo(src, className = '', props = {}, addMuteToggle = false) {
  const video = createElement('video', {
    classes: className,
  });

  if (props.muted || props.autoplay) {
    video.muted = true;
  }

  if (props) {
    Object.keys(props).forEach((propName) => {
      const value = props[propName];
      if (typeof value !== 'boolean') {
        video.setAttribute(propName, value);
      } else if (value) {
        video.setAttribute(propName, '');
      }
    });
  }

  const source = createElement('source', {
    props: {
      src,
      type: 'video/mp4',
    },
  });

  video.appendChild(source);

  const wrapper = createElement('div', { classes: className });
  wrapper.appendChild(video);

  if (!props.controls) {
    setTimeout(() => {
      setPlaybackControls(wrapper);
    }, 0);
  }

  if (addMuteToggle) {
    appendMuteToggleButton(wrapper);
  }

  if (props.autoplay) {
    requestAnimationFrame(() => {
      const wrapperParent = wrapper.closest('.v2-embed, .v2-video');
      if (wrapperParent) {
        observeAutoplayWhenVisible({
          target: video,
          play: () => safePlay(video),
          pause: () => video.pause(),
          threshold: [0, 1.0],
          debounceMs: 100,
        });
      } else {
        safePlay(video);
      }
    });
  }

  return wrapper;
}

export function getDynamicVideoHeight(video) {
  // Get the element's height(use requestAnimationFrame to get actual height instead of 0)
  requestAnimationFrame(() => {
    const height = video.offsetHeight - 60;
    const playbackControls = video.parentElement?.querySelector('.v2-video__playback-button');
    if (!playbackControls) {
      return;
    }

    playbackControls.style.top = `${height}px`;
  });

  // Get the element's height on resize
  const getVideoHeight = (entries) => {
    for (const entry of entries) {
      const height = entry.target.offsetHeight - 60;
      const playbackControls = video.parentElement?.querySelector('.v2-video__playback-button');
      if (!playbackControls) {
        return;
      }
      playbackControls.style.top = `${height}px`;
    }
  };

  const resizeObserver = new ResizeObserver(getVideoHeight);
  resizeObserver.observe(video);
}

/**
 * Creates a video element with a poster image.
 * @param {string} linkUrl - Video URL.
 * @param {HTMLPictureElement} poster - Poster image.
 * @param {string} className - The name of the CSS block for styling.
 * @param {Object} videoConfig - Properties for video player.
 * @return {HTMLElement} - The container element that holds the video and poster.
 */
export function createVideoWithPoster(linkUrl, poster, className, videoConfig = {}, configs = {}) {
  const defaultConfig = {
    muted: false,
    autoplay: false,
    loop: false,
    playsinline: true,
    controls: true,
  };

  const config = {
    ...defaultConfig,
    ...videoConfig,
  };

  const { addMuteToggle = false } = configs;

  const videoContainer = document.createElement('div');

  if (className) {
    videoContainer.classList.add('video-wrapper', className);
  }

  if (poster) {
    videoContainer.append(poster);
  }

  const loadAndSetupPlayer = async (videoUrl) => {
    const player = await setupPlayer(videoUrl, videoContainer, {
      fill: true,
      ...config,
    });

    const video = videoContainer.querySelector('.video-js');
    video.style.display = 'none';

    if (addMuteToggle) {
      appendMuteToggleButton(videoContainer);
    }

    return player;
  };

  if (isLowResolutionVideoUrl(linkUrl)) {
    const videoOrIframe = createProgressivePlaybackVideo(linkUrl, 'video-wrapper', config, addMuteToggle);
    if (poster) {
      const posterSrc = poster.querySelector('img')?.src;
      videoOrIframe.querySelector('video')?.setAttribute('poster', posterSrc);
      poster.remove();
    }
    videoContainer.append(videoOrIframe);
  } else {
    const videoUrl = getDeviceSpecificVideoUrl(linkUrl);
    if (config.autoplay) {
      (async () => {
        const player = await loadAndSetupPlayer(videoUrl);
        const video = videoContainer.querySelector('.video-js');
        if (config.autoplay) {
          player.on('loadeddata', () => {
            if (poster) {
              video.style.display = '';
              if (video.parentElement.classList.contains('video-js')) {
                video.parentElement.style.display = '';
              }
              poster.style.display = 'none';
              if (!config.controls) {
                setPlaybackControls(videoContainer);
              }
            }
          });
        }
      })();
    } else {
      async function initializePlayerWithControls() {
        await loadAndSetupPlayer(videoUrl);
        setPlaybackControls(videoContainer);
        if (addMuteToggle) {
          appendMuteToggleButton(videoContainer);
        }
      }
      initializePlayerWithControls();
    }
  }
  return videoContainer;
}

/**
 * Creates a video wrapper element for the given source.
 * Supports progressive MP4, AEM (Video.js), and YouTube (iframe or API mode).
 *
 * @param {HTMLAnchorElement|string} link Anchor containing a video URL or a direct video URL.
 * @param {string} [className=''] CSS class(es) applied to the wrapper element.
 * @param {Object} [videoParams={}] Player options (muted, autoplay, controls, loop, playsinline, title).
 * @param {Object} [configs={}] Additional configuration flags.
 * @param {boolean} [configs.usePosterAutoDetection] Auto-detect a poster image from the anchor context.
 * @param {boolean} [configs.addMuteToggle] Adds a custom mute toggle when supported.
 * @returns {HTMLElement|null} Wrapper element containing the appropriate video implementation, or null if invalid.
 */
export const createVideo = (link, className = '', videoParams = {}, configs = {}) => {
  let src;
  let poster;

  const { usePosterAutoDetection, addMuteToggle = false } = configs;

  if (link instanceof HTMLAnchorElement) {
    const config = parseVideoLink(link, usePosterAutoDetection);
    if (!config) {
      return null;
    }

    src = config.url;
    poster = config.poster;
  } else {
    src = link;
  }

  if (isLowResolutionVideoUrl(src)) {
    return createProgressivePlaybackVideo(src, className, videoParams, addMuteToggle);
  }

  if (isYoutubeVideoUrl(src)) {
    return createYouTubeVideoWrapper(src, className, videoParams, poster);
  }

  if (poster) {
    return createVideoWithPoster(src, poster, className, videoParams, { addMuteToggle });
  }

  const container = document.createElement('div');
  container.classList.add(className);

  const videoUrl = getDeviceSpecificVideoUrl(src);

  async function initializePlayerWithControls() {
    await setupPlayer(videoUrl, container, videoParams, null);

    if (!videoParams.controls) {
      setPlaybackControls(container);
    }

    if (addMuteToggle) {
      appendMuteToggleButton(container);
    }
  }

  initializePlayerWithControls();

  return container;
};

const logVideoEvent = (eventName, videoId, timeStamp, blockName = 'video') => {
  console.info(`[${blockName}] ${eventName} for ${videoId} at ${timeStamp}`);
};

const formatDebugTime = (date) => {
  const timeOptions = {
    hour12: false,
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  };
  const formattedTime = date.toLocaleTimeString('en-US', timeOptions);
  const milliseconds = date.getMilliseconds().toString().padStart(3, '0');

  return `${formattedTime}.${milliseconds}`;
};

export const handleVideoMessage = (event, videoId, blockName = 'video') => {
  if (!event.origin.endsWith(aemCloudDomain)) {
    return;
  }
  if (event.data.type === 'embedded-video-player-event') {
    const timeStamp = formatDebugTime(new Date());

    logVideoEvent(event.data.name, event.data.videoId, timeStamp, blockName);

    if (event.data.name === 'video-config' && event.data.videoId === videoId) {
      console.info('Sending video config:', getVideoConfig(videoId), timeStamp);
      event.source.postMessage(JSON.stringify(getVideoConfig(videoId)), '*');
    }

    // TODO: handle events when needed in a block
    // switch (event.data.name) {
    //   case 'video-playing':
    //   case 'video-play':
    //   case 'video-ended':
    //   case 'video-loadedmetadata':
    //     logVideoEvent(event.data.name, event.data.videoId, timeStamp, blockName);
    //     break;
    //   default:
    //     break;
    // }
  }
};

/**
 * Checks if the current page contains any known video-related elements.
 * @returns {boolean} True if a video block is found.
 */
export function hasVideoOnPage() {
  return !!(
    document.querySelector('.video-js') ||
    document.querySelector('.text-link-with-video') ||
    document.querySelector('.v2-video__big-play-button')
  );
}

/**
 * Dynamically loads Video.js script and CSS and dispatches an event once loaded.
 * @returns {Promise<void>}
 */
export async function loadVideoJs() {
  await Promise.all([loadCSS(VIDEO_JS_CSS), loadScript(VIDEO_JS_SCRIPT)]);

  const jsScript = document.querySelector(`head > script[src="${VIDEO_JS_SCRIPT}"]`);
  const cssScript = document.querySelector(`head > link[href="${VIDEO_JS_CSS}"]`);

  jsScript.dataset.loaded = true;
  cssScript.dataset.loaded = true;

  document.dispatchEvent(new Event('videojs-loaded'));
}

class VideoEventManager {
  constructor() {
    this.registrations = [];
    window.addEventListener('message', this.handleMessage.bind(this));
  }

  register(videoId, blockName, callback) {
    this.registrations.push({ videoId, blockName, callback });
  }

  unregister(videoId, blockName) {
    this.registrations = this.registrations.filter((reg) => reg.videoId !== videoId || reg.blockName !== blockName);
  }

  handleMessage(event) {
    this.registrations.forEach(({ videoId, blockName, callback }) => {
      if (event.data.type === 'embedded-video-player-event' && event.data.videoId === videoId) {
        callback(event, videoId, blockName);
      }
    });
  }
}

export { VideoEventManager };
